1	'use strict';
2	// breach/adjudicator/verdict.js - THE adjudication-abstention gate (P3 Wave-2c, GAPS.md P0).
3	//
4	// THE DISEASE (caution.md C-082, C-086, C-092, and Constitution Rule 6):
5	//   The old adjudicator's verdict enum had a "maybe-ships" gap. An ambiguous entailment verdict
6	//   ("Unclear, leaning no") matched NEITHER the breach nor the clear branch, so the finding stayed
7	//   CONFIRMED with its fine attached. Separately, a NO_BREACH clearance was accepted on the model's
8	//   bare say-so, with no proof, so the model could clear a real breach simply by asserting it away.
9	//
10	// THE RULE THIS ENFORCES (Constitution Rule 6 + Rule 12 gate 4 - abstain by default):
11	//   parseVerdict maps the model's closed enum { breach | no_breach | insufficient } to the engine's
12	//   closed three-state { violation | needs_review | pass }:
13	//     breach        -> violation      (an adjudicated breach; this is what ships)
14	//     no_breach     -> pass           BUT ONLY with a verbatim disproof anchored in the supplied
15	//                                     evidence (C-092). Without it: needs_review, never pass.
16	//     insufficient  -> needs_review   (not a breach, not a clearance)
17	//   ANYTHING ELSE - a missing verdict, an unknown enum value, a wrong-typed field, one of our own
18	//   internal state names echoed back, or any shape the model was never allowed to emit - maps to
19	//   needs_review. There is NO branch that keeps an accusation on an unparseable answer. Abstention is
20	//   the default and the cheapest path; a claim is released only on an explicit, well-formed verdict.
21	//
22	// This module is PURE: a function of (raw verdict, evidence text). No I/O, no network, no LLM call.
23	
24	// The model's CLOSED verdict enum. Anything outside this set is not a verdict; it is noise -> abstain.
25	const LLM_VERDICTS = new Set(['breach', 'no_breach', 'insufficient']);
26	// VERDICTS: the engine's CLOSED three-state (axe-core doctrine), the ONE canonical spelling (underscore
27	// token in code; CONSTITUTION prose uses hyphenated English). This is the one door for the three-state
28	// enum (ledger decision 5): every consumer imports it rather than re-declaring the strings, so a
29	// hyphen/underscore drift (llm/prompts/adjudicate.js's old 'needs-review') cannot recur. No fourth
30	// "maybe" value exists.
31	const VERDICTS = Object.freeze(['violation', 'needs_review', 'pass']);
32	const STATES = new Set(VERDICTS);
33	// The base mapping. no_breach -> pass is CONDITIONAL on a verbatim disproof (see parseVerdict).
34	const VERDICT_TO_STATE = { breach: 'violation', no_breach: 'pass', insufficient: 'needs_review' };
35	
36	const MIN_DISPROOF_CHARS = 6;   // a sub-6-char "disproof" is a nav fragment, never proof (cf. C-089)
37	const DISPROOF_ANCHOR_CHARS = 40; // the leading span that must appear verbatim in the evidence
38	
39	// verdictWord(raw) -> the lowercased verdict string carried by a raw verdict (a { verdict } object or
40	// a bare string), or null when none is present. Non-string verdict fields are null (a wrong type is
41	// not a verdict).
42	function verdictWord(raw) {
43	  if (typeof raw === 'string') return raw.toLowerCase().trim();
44	  if (raw && typeof raw.verdict === 'string') return raw.verdict.toLowerCase().trim();
45	  return null;
46	}
47	
48	// normaliseVerdict(raw) -> a member of LLM_VERDICTS, or null for anything outside the closed enum
49	// (missing, unknown, extra-state, wrong type). The whole safety property rests on this returning null
50	// rather than guessing.
51	function normaliseVerdict(raw) {
52	  const v = verdictWord(raw);
53	  return v && LLM_VERDICTS.has(v) ? v : null;
54	}
55	
56	// normaliseDisproof(disproof) -> the disproof lowercased, trimmed, and stripped of surrounding quotes.
57	// A non-string disproof normalises to '' (which fails the length gate below).
58	function normaliseDisproof(disproof) {
59	  if (typeof disproof !== 'string') return '';
60	  return disproof.toLowerCase().trim().replace(/^["'`]+/, '').replace(/["'`]+$/, '').trim();
61	}
62	
63	/**
64	 * disproofMatches(disproof, evidence) -> true when `disproof` is a real verbatim span of `evidence`.
65	 * The proven port rubric (C-092): normalise, require a minimum length, and require the evidence
66	 * haystack to contain the disproof's leading anchor span. A disproof the engine cannot find in the
67	 * evidence it handed the model is not a disproof.
68	 */
69	function disproofMatches(disproof, evidence) {
70	  const q = normaliseDisproof(disproof);
71	  if (q.length < MIN_DISPROOF_CHARS) return false;
72	  const hay = typeof evidence === 'string' ? evidence.toLowerCase() : '';
73	  if (!hay) return false;
74	  return hay.includes(q.slice(0, DISPROOF_ANCHOR_CHARS));
75	}
76	
77	function reasonOf(raw, fallback) {
78	  const r = raw && typeof raw.reason === 'string' ? raw.reason.trim() : '';
79	  return (r || fallback || '').slice(0, 160);
80	}
81	
82	function abstain(verdict, reason) {
83	  return { state: 'needs_review', verdict: verdict || null, reason, disproof: null };
84	}
85	
86	/**
87	 * parseVerdict(raw, evidence) -> { state, verdict, reason, disproof }
88	 *   state    the closed three-state: 'violation' | 'needs_review' | 'pass'.
89	 *   verdict  the normalised model verdict ('breach'|'no_breach'|'insufficient') or null if unparseable.
90	 *   reason   a short human-readable cause (the model's own reason when present, else a fixed default).
91	 *   disproof the verbatim disproof span (only on a `pass`; null otherwise).
92	 *
93	 * `evidence` is the text the model was shown (see adjudicate.js `evidenceText`); it is required to
94	 * clear a no_breach. If evidence is omitted or empty, a no_breach can NEVER reach `pass` (it abstains
95	 * to needs_review) - the safe direction: you cannot clear a claim against text you were not shown
96	 * (the port's HARD RULE 4).
97	 */
98	function parseVerdict(raw, evidence) {
99	  const v = normaliseVerdict(raw);
100	  if (v === null) return abstain(null, 'unparseable, missing or out-of-enum verdict -> abstain (Rule 6)');
101	  if (v === 'breach') {
102	    return { state: 'violation', verdict: 'breach', reason: reasonOf(raw, 'adjudicated breach'), disproof: null };
103	  }
104	  if (v === 'insufficient') {
105	    return abstain('insufficient', reasonOf(raw, 'insufficient evidence to rule either way -> abstain'));
106	  }
107	  // v === 'no_breach': clears to pass ONLY with a verbatim disproof anchored in the evidence (C-092).
108	  const disproof = raw && raw.disproof;
109	  if (disproofMatches(disproof, evidence)) {
110	    return { state: 'pass', verdict: 'no_breach', reason: reasonOf(raw, 'false positive, disproved verbatim'), disproof: normaliseDisproof(disproof) };
111	  }
112	  return abstain('no_breach', 'no_breach with no verbatim disproof anchored in the evidence (C-092) -> abstain');
113	}
114	
115	module.exports = {
116	  parseVerdict,
117	  normaliseVerdict,
118	  disproofMatches,
119	  normaliseDisproof,
120	  LLM_VERDICTS,
121	  VERDICTS,
122	  STATES,
123	  VERDICT_TO_STATE,
124	  MIN_DISPROOF_CHARS,
125	  DISPROOF_ANCHOR_CHARS,
126	};
127

1	'use strict';
2	// llm/entailment.js - GATE 3: the NLI entailment step (Constitution Rule 12 gate 3, Rule 11;
3	// caution.md C-147; GAPS.md llm-unverified). The deterministic shell that turns each atomic claim
4	// into a hypothesis, its cited span into a premise, and runs an INJECTED model as an NLI verifier.
5	// Anything not labelled `entailment` is refused; the failure mode is abstention, never a guess.
6	//
7	// NO NETWORK. The model caller is INJECTED (`llmCall`), exactly like breach/adjudicator/adjudicate.js;
8	// this module owns only: prompt assembly (llm/prompts/entailment.js), a HARD per-call deadline
9	// (Rule 9, reusing llm/router.js withDeadline), the post-hoc structural gate (llm/gate.js
10	// validateResponse: schema + retrieval-gate + quote-match), and the verdict -> ok reduction.
11	//
12	// checkEntailment(claims, { llmCall, deadlineMs, now, log }) -> Promise<Array<{
13	//   claim, premise_source_id, verdict: 'entailment'|'neutral'|'contradiction', ok:boolean, reason
14	// }>>
15	//   - one result per input claim, IN ORDER (the array is built by mapping the INPUT, never the model
16	//     output: like the adjudicator, this shell is filter-only and can neither add nor drop a claim).
17	//   - ok:true ONLY when the gate-validated verdict is exactly 'entailment'. neutral, contradiction,
18	//     a gate rejection (out-of-set source_id, bad schema, unparseable), a timeout or a throw all
19	//     yield ok:false with verdict defaulted to the conservative 'neutral' (abstain-by-default,
20	//     Rule 12 gate 4). The consumer (the adjudicator, wired by Rob) demotes any ok:false to
21	//     needs_review; it NEVER ships as a violation.
22	//
23	// WIRING NOTE FOR ROB (do not wire here; R3 owns breach/adjudicator/adjudicate.js): after a text
24	// candidate is ruled `breach` and before stampFromVerdict writes `violation`, gate it through
25	//   const [e] = await checkEntailment(
26	//     [{ claim: f.description, premise_source_id: f.evidence_source_id || f.evidence_url,
27	//        premise: f.evidence_quote }],
28	//     { llmCall: opts.llmCall, deadlineMs: remaining });
29	//   if (!e || !e.ok) demote the finding to needs_review (adjudication_reason: 'nli:' + e.verdict).
30	// The premise MUST be the exact verbatim span the quote-match verifier already string-matched to the
31	// corpus (Rule 12 gate 2 feeds gate 3), so the NLI premise is grounded, not paraphrased.
32	
33	const { withDeadline } = require('./router.js');
34	const { validateResponse } = require('./gate.js');
35	const { buildEntailmentPrompt, LABELS } = require('./prompts/entailment.js');
36	
37	const DEFAULT_DEADLINE_MS = 9000; // a CAP, never a floor (Rule 8); one NLI call is bounded to seconds.
38	const ENTAILMENT = 'entailment';
39	const ABSTAIN_LABEL = 'neutral'; // the conservative default label on any refusal (not entailment).
40	
41	// numOr(v, d): a positive finite number, else the default. A misconfigured deadline never becomes a
42	// floor or an unbounded wait; it falls back to the CAP default (Rule 8).
43	function numOr(v, d) {
44	  const n = Number(v);
45	  return Number.isFinite(n) && n > 0 ? n : d;
46	}
47	
48	// normaliseClaim(claim): read the hypothesis, its premise span and that span's source_id off one
49	// input claim, tolerating the field spellings the proposer/verifier flow uses. Never re-derives a
50	// fact; it only reads the fields it was handed (Rule 1).
51	function normaliseClaim(claim) {
52	  const c = claim || {};
53	  const hypothesis = firstString([c.claim, c.hypothesis, c.text, c.description]);
54	  const sourceId = firstString([c.premise_source_id, c.source_id, c.sourceId, c.evidence_source_id, c.evidence_url]);
55	  const premise = firstString([c.premise, c.premise_text, c.span, c.evidence_quote, c.quote]);
56	  return { hypothesis, sourceId, premise };
57	}
58	
59	// firstString(cands): the first non-empty string in a candidate list, else '' (fail-closed: a missing
60	// field becomes an empty string that the abstain guards below reject, never a fabricated default).
61	function firstString(cands) {
62	  for (const v of cands) {
63	    if (typeof v === 'string' && v.trim()) return v;
64	  }
65	  return '';
66	}
67	
68	// resultFor(claim, sourceId, verdict, ok, reason): the one canonical result row shape.
69	function resultFor(hypothesis, sourceId, verdict, ok, reason) {
70	  return { claim: hypothesis, premise_source_id: sourceId, verdict, ok, reason };
71	}
72	
73	// callModel(prompt, opts): one HARD-deadline-bounded attempt at the injected caller. Returns the raw
74	// model return on success, or a typed abstain marker ({ _abstain, reason }) on timeout/throw. A
75	// synchronous throw in llmCall is turned into a rejection by Promise.resolve().then so withDeadline
76	// captures it as a first-class value (never an uncaught throw into the mint).
77	async function callModel(pkg, opts) {
78	  const request = {
79	    role: 'extract', system: pkg.system, prompt: pkg.prompt, schema: pkg.schema,
80	    allowedSourceIds: pkg.allowedSourceIds, sources: pkg.sources,
81	    temperature: 0, max_tokens: 400, deadline_ms: opts.deadlineMs,
82	  };
83	  const work = Promise.resolve().then(() => opts.llmCall(request));
84	  const raced = await withDeadline(work, opts.deadlineMs);
85	  if (raced.timedOut) return { _abstain: true, reason: 'nli call exceeded the ' + opts.deadlineMs + 'ms deadline -> abstain (Rule 9)' };
86	  if (raced.error !== undefined) return { _abstain: true, reason: 'nli call threw: ' + String(raced.error).slice(0, 80) + ' -> abstain (Rule 4)' };
87	  return { value: raced.value };
88	}
89	
90	// verdictFromResponse(raw, pkg): run the injected caller's return through llm/gate.js and reduce it
91	// to { verdict, ok, reason }. A gate rejection (schema, out-of-set source_id, quote drift) or a
92	// missing/unknown label abstains; only a clean, gate-valid 'entailment' is ok:true.
93	function verdictFromResponse(raw, pkg) {
94	  const gated = validateResponse(raw, { schema: pkg.schema, allowedSourceIds: pkg.allowedSourceIds, sources: pkg.sources });
95	  if (!gated.ok) {
96	    const code = (gated.violations && gated.violations[0] && gated.violations[0].code) || 'gate_reject';
97	    return { verdict: ABSTAIN_LABEL, ok: false, reason: 'gate rejected the nli response (' + code + ') -> abstain' };
98	  }
99	  const label = String((gated.value && gated.value.verdict) || '').toLowerCase().trim();
100	  if (!LABELS.includes(label)) return { verdict: ABSTAIN_LABEL, ok: false, reason: 'nli label not in the closed enum -> abstain' };
101	  if (label === ENTAILMENT) return { verdict: ENTAILMENT, ok: true, reason: 'premise entails the hypothesis' };
102	  return { verdict: label, ok: false, reason: 'nli label "' + label + '" is not entailment -> abstain (Rule 12 gate 3)' };
103	}
104	
105	// checkOne(claim, opts): the whole per-claim pipeline. A claim missing its premise or its source_id
106	// cannot be verified, so it abstains WITHOUT calling the model (no premise, nothing to entail).
107	async function checkOne(claim, opts) {
108	  const { hypothesis, sourceId, premise } = normaliseClaim(claim);
109	  if (!sourceId || !premise) {
110	    return resultFor(hypothesis, sourceId, ABSTAIN_LABEL, false, 'no cited premise span/source_id -> cannot verify, abstain (Rule 3)');
111	  }
112	  if (typeof opts.llmCall !== 'function') {
113	    return resultFor(hypothesis, sourceId, ABSTAIN_LABEL, false, 'no llmCall injected -> abstain (Rule 12 gate 4)');
114	  }
115	  const pkg = buildEntailmentPrompt({ hypothesis, premise, sourceId });
116	  const called = await callModel(pkg, opts);
117	  if (called._abstain) return resultFor(hypothesis, sourceId, ABSTAIN_LABEL, false, called.reason);
118	  const v = verdictFromResponse(called.value, pkg);
119	  logSafe(opts.log, { event: 'nli', source_id: sourceId, verdict: v.verdict, ok: v.ok });
120	  return resultFor(hypothesis, sourceId, v.verdict, v.ok, v.reason);
121	}
122	
123	// logSafe(log, event): emit to an optional observability sink; a throwing sink can never break a
124	// verification (FAIL-OPEN: an observability fault is not a legal-claim failure, dropped on purpose).
125	function logSafe(log, event) {
126	  if (typeof log !== 'function') return;
127	  try { log(event); } catch (_e) { /* FAIL-OPEN: log sink faults are non-fatal, deliberately dropped */ }
128	}
129	
130	/**
131	 * checkEntailment(claims, opts) -> Promise<result[]>. Runs each claim through the NLI gate SEQUENTIALLY
132	 * (so per-claim deadlines compose predictably and a shared free-tier is not stormed). The output array
133	 * is a strict 1:1 map of the INPUT (filter-only): |result| === |claims|, always.
134	 *
135	 * opts.llmCall    async (request) => model response (raw string, {text}, or {ok,text}); INJECTED, this
136	 *                 module never opens a socket. Absent/throws/times out/unparseable -> the claim abstains.
137	 * opts.deadlineMs the per-call hard deadline (default 9000); a CAP, never a floor (Rule 8/9).
138	 * opts.now/opts.log  reserved clock + optional observability sink (both optional).
139	 */
140	async function checkEntailment(claims, options = {}) {
141	  const list = Array.isArray(claims) ? claims : [];
142	  const opts = {
143	    llmCall: typeof options.llmCall === 'function' ? options.llmCall : null,
144	    deadlineMs: numOr(options.deadlineMs, DEFAULT_DEADLINE_MS),
145	    log: typeof options.log === 'function' ? options.log : null,
146	  };
