196	// validateSchema(value, schema, path): the recursive shape check. A type mismatch short-circuits (deeper
197	// checks on the wrong shape are noise); otherwise scalar bounds, object and array rules all apply.
198	function validateSchema(value, schema, path) {
199	  if (!schema || typeof schema !== 'object') return [];
200	  if (schema.nullable && value === null) return [];
201	  if (schema.type && !typeMatches(value, schema.type)) {
202	    return [sv(path, 'expected ' + JSON.stringify(schema.type) + ', got ' + typeOf(value))];
203	  }
204	  const out = checkScalarConstraints(value, schema, path);
205	  if (typeOf(value) === 'object') out.push(...checkObject(value, schema, path));
206	  else if (Array.isArray(value)) out.push(...checkArray(value, schema, path));
207	  return out;
208	}
