29	// Free-first family ranking, ported from the proven chain order in cowork-os src/lib/llm/router.js
30	// (Cloudflare Workers AI -> Groq -> NIM -> Gemini -> ... -> paid last). This is the ONE place the
31	// order lives; callers may pass providers in any order and orderProviders() re-imposes free-first.
32	const FAMILY_ORDER = ['cloudflare', 'groq', 'nim', 'gemini', 'deepseek', 'perplexity', 'openai', 'qwen', 'anthropic'];
33	const PAID_FAMILIES = new Set(['deepseek', 'perplexity', 'openai', 'qwen', 'anthropic']);
34	
35	// A short per-call cap by default. The old estate's 30s+ per-provider waits were the hang vector
36	// (caution.md C-040/C-138); a routed classification/adjudication call is bounded to seconds.
37	const DEFAULT_DEADLINE_MS = 9000;
38	
39	// assertDeadline(ms): a budget cap must be a positive finite number. A misconfigured cap must SHOUT,
40	// not silently degrade (caution.md C-025: sub-floor budgets throw at the boundary, never pass quietly).
41	function assertDeadline(ms) {
42	  if (typeof ms !== 'number' || !Number.isFinite(ms) || ms <= 0) {
43	    throw new Error('llm/router: deadlineMs must be a positive finite number, got ' + JSON.stringify(ms));
44	  }
45	}
