93	// withDeadline(promise, ms, onTimeout): resolve { timedOut:false, value } when `promise` settles
94	// first, or { timedOut:true } when the cap fires first. The abandoned promise gets a no-op catch so
95	// a late rejection cannot surface as an unhandled rejection. No floor, no minimum wait (Rule 8).
96	function withDeadline(promise, ms, onTimeout) {
97	  let timer = null;
98	  const settled = promise.then(
99	    (value) => ({ timedOut: false, value }),
100	    (error) => ({ timedOut: false, value: null, error })
101	  );
102	  const timeout = new Promise((resolve) => {
103	    timer = setTimeout(() => { if (onTimeout) onTimeout(); resolve({ timedOut: true }); }, ms);
104	    if (timer && typeof timer.unref === 'function') timer.unref();
105	  });
106	  return Promise.race([settled, timeout]).finally(() => { if (timer) clearTimeout(timer); });
107	}
108	
109	// interpretResponse(response): reduce an injected caller's return to { ok, text, error } at the
110	// transport level. { ok:false } or empty text is a provider-level failure the chain falls over.
111	function interpretResponse(response) {
112	  if (response == null) return { ok: false, text: '', error: 'null_response' };
113	  if (typeof response === 'string') {
114	    return response.trim() ? { ok: true, text: response } : { ok: false, text: '', error: 'empty_text' };
115	  }
116	  if (response.ok === false) return { ok: false, text: '', error: String(response.error || 'provider_error') };
117	  const text = typeof response.text === 'string' ? response.text : '';
118	  if (!text.trim()) return { ok: false, text: '', error: 'empty_text' };
119	  return { ok: true, text };
120	}
