129	// callProvider(provider, task, deadlineMs, validate, log): one deadline-bounded attempt at one
130	// provider. Returns { ok, value?, text?, response?, record }. `record` is always populated for the
131	// attempts ledger (Part B Rule 9: log every routing decision). A structural `validate` (llm/gate.js)
132	// turns a transport success into a routing success ONLY when the response also passes the gate - a
133	// fluent-but-hallucinated answer must not win just because the socket returned 200.
134	async function callProvider(provider, task, deadlineMs, validate, log) {
135	  const t0 = Date.now();
136	  const controller = new AbortController();
137	  // withDeadline converts BOTH a fulfilment and a rejection into a resolved result, so a throwing
138	  // injected caller is a first-class value here (raced.error), never an uncaught throw - no catch
139	  // is needed, and a rejection cleanly falls the chain OVER to the next provider (fail-closed system).
140	  const raced = await withDeadline(
141	    Promise.resolve().then(() => provider.call(task, { signal: controller.signal })),
142	    deadlineMs,
143	    () => controller.abort()
144	  );
145	  const ms = Date.now() - t0;
146	  const base = { provider: provider.name, family: provider.family, ms };
147	  if (raced.timedOut) return finalize(base, 'timeout', null, log);
148	  if (raced.error !== undefined) return finalize(base, 'threw:' + errText(raced.error), null, log);
149	  const interp = interpretResponse(raced.value);
150	  if (!interp.ok) return finalize(base, interp.error, null, log);
151	  if (typeof validate === 'function') return validated(base, interp, raced.value, validate, log);
152	  return { ok: true, text: interp.text, response: raced.value, record: logged(base, 'ok', log) };
153	}
