157	function validated(base, interp, raw, validate, log) {
158	  const verdict = validate(raw != null ? raw : interp.text);
159	  if (verdict && verdict.ok) {
160	    return { ok: true, value: verdict.value, text: interp.text, response: raw, record: logged(base, 'ok', log) };
161	  }
162	  const reason = 'gate_reject:' + firstViolationCode(verdict);
163	  return finalize(base, reason, null, log);
