187	// route(task, opts): try providers free-first, one deadline-bounded attempt each, and return the
188	// first success. `validate` (llm/gate.js) is optional but recommended: it makes a hallucinated
189	// response lose to the next provider instead of winning. Exhaustion returns an abstain, never a guess.
190	async function route(task, opts = {}) {
191	  const { providers = [], deadlineMs = DEFAULT_DEADLINE_MS, log = null, validate = null } = opts;
192	  assertDeadline(deadlineMs);
193	  const ordered = orderProviders(providers);
194	  const attempts = [];
195	  if (!ordered.length) return { ok: false, reason: 'no_providers', text: '', attempts };
196	  for (const provider of ordered) {
197	    const outcome = await callProvider(provider, task, deadlineMs, validate, log);
198	    attempts.push(outcome.record);
199	    if (outcome.ok) {
200	      return {
201	        ok: true, provider: outcome.record.provider, family: outcome.record.family,
202	        text: outcome.text, value: outcome.value, response: outcome.response, attempts,
203	      };
204	    }
205	  }
206	  return { ok: false, reason: 'all_providers_exhausted', text: '', attempts };
207	}
