209	// defaultVeto(vote): the standing veto polarity for a findings jury (Part A Pattern 5: weak judges
210	// have high true-positive but very low true-negative rates, so a REJECTION is the trustworthy signal
211	// and veto-to-reject is the correct polarity). A juror vetoes when it declares an explicit veto, or
212	// when its validated verdict is anything other than the affirmative 'violation'.
213	function defaultVeto(vote) {
214	  const v = (vote && vote.value) || {};
215	  if (v.veto === true) return { veto: true, reason: String(v.reason || 'explicit_veto').slice(0, 80) };
216	  if (typeof v.verdict === 'string' && v.verdict !== 'violation') {
217	    return { veto: true, reason: 'verdict=' + v.verdict };
218	  }
219	  return { veto: false };
220	}
221	
222	// firstVeto(valid, vetoRule): the first juror to veto, or null when the jury is unanimous.
223	function firstVeto(valid, vetoRule) {
224	  for (const vote of valid) {
225	    const r = vetoRule(vote);
226	    if (r && r.veto) return { provider: vote.provider, reason: String(r.reason || 'veto') };
227	  }
228	  return null;
229	}
230	
231	// collectVotes(jurors, task, deadlineMs, validate, log): call each juror, gate.js-validate each
232	// response BEFORE it may vote (Rule 12: gates 1-4 run per response), and return the vote ledger.
233	async function collectVotes(jurors, task, deadlineMs, validate, log) {
234	  const votes = [];
235	  for (const juror of jurors) {
236	    const outcome = await callProvider(juror, task, deadlineMs, validate, log);
237	    if (outcome.ok) votes.push({ provider: juror.name, family: juror.family, value: outcome.value != null ? outcome.value : { text: outcome.text } });
238	    else votes.push({ provider: juror.name, family: juror.family, value: null, invalid: outcome.record.outcome });
239	  }
240	  return votes;
241	}
