257	  const jurors = distinctFamilyProviders(orderProviders(providers), n);
258	  if (jurors.length < n) {
259	    return { ok: false, verdict: 'reject', reason: 'insufficient_independent_families:' + jurors.length + '<' + n, votes: [] };
260	  }
261	  const votes = await collectVotes(jurors, task, deadlineMs, validate, log);
262	  const valid = votes.filter((v) => v.value != null);
263	  if (valid.length < n) return { ok: false, verdict: 'reject', reason: 'insufficient_valid_votes:' + valid.length + '<' + n, votes };
264	  const veto = firstVeto(valid, vetoRule);
265	  if (veto) return { ok: false, verdict: 'reject', reason: 'veto[' + veto.provider + ']:' + veto.reason, votes };
266	  return { ok: true, verdict: 'accept', votes };
267	}
