175	function addTrackerBreaches(observed, pre) {
176	  for (const host of uniqueHosts(pre.trackers)) {
177	    const ev = firstTrackerForHost(pre.trackers, host);
178	    observed.push({
179	      kind: 'tracker_request_pre_consent',
180	      name: host,
181	      host,
182	      essential: false,
183	      networkEvent: ev,
184	      artifact: { type: 'network_request', networkEvent: ev },
185	      ts: (ev && ev.ts) || pre.ts,
186	    });
187	  }
188	}
