234	async function checkConsentControl(control, cfg) {
235	  if (!control || !control.found) return unknownControl();
236	  const url = control.url || null;
237	  if (!url) return { found: true, healthy: null, url: null };
238	  const health = await linkHealth(url, cfg);
239	  return { found: true, healthy: health.healthy, url };
