260	async function runObservation(url, cfg, launcher, holder) {
261	  const browser = await launcher();
262	  holder.browser = browser;
263	  const page = await browser.newPage();
264	  const capture = attachNetworkCapture(page, cfg);
265	  await navigateUntouched(page, url, cfg);
266	  const pre = await snapshotState(page, capture, cfg);   // BEFORE any consent interaction
267	  const control = await safeFindControl(page);
268	  const consentControl = await checkConsentControl(control, cfg);
269	  await attemptConsent(page, control);                    // injected clicker (accept)
270	  const post = await snapshotState(page, capture, cfg);   // AFTER consent, for the diff
271	  const observed = buildObserved(pre, consentControl, cfg);
272	  await browser.close();
273	  holder.browser = null;
274	  return laneRan(observed, consentControl, diffSummary(pre, post, cfg), cfg);
