1	'use strict';
2	/**
3	 * extract.js - the crawler's HTML -> evidence extractor. THE ONE producer of stripped visible text for
4	 * the corpus (caution.md C-012: sector/rule matching never runs on <script>/<style>/markup noise; the
5	 * evidence quote is cut from exactly this text, C-035). Pure and synchronous over an HTML string; no
6	 * network, no clock, no env. Every corpus page and the footer surface (C-034) come out of here.
7	 *
8	 * pageContentClass() is the C-031/C-032/C-038 guard: a login/challenge/error/SPA-shell response is
9	 * classified by its CONTENT, not its byte count, so a login or bot-wall page can never flip a site to
10	 * "reachable" or become an absence-finding surface.
11	 */
12	
13	const NAMED_ENTITIES = {
14	  amp: '&', lt: '<', gt: '>', quot: '"', apos: "'", nbsp: ' ', '#39': "'",
15	  ndash: '-', mdash: '-', hellip: '...', copy: '(c)', reg: '(R)', trade: '(TM)',
16	  pound: '£', euro: '€', middot: '·', bull: '•',
17	};
18	
19	function decodeEntities(s) {
20	  return String(s).replace(/&(#x?[0-9a-fA-F]+|[a-zA-Z]+);/g, (m, g) => {
21	    const key = g.toLowerCase();
22	    if (Object.prototype.hasOwnProperty.call(NAMED_ENTITIES, key)) return NAMED_ENTITIES[key];
23	    if (g[0] === '#') {
24	      const code = (g[1] === 'x' || g[1] === 'X') ? parseInt(g.slice(2), 16) : parseInt(g.slice(1), 10);
25	      if (Number.isFinite(code) && code >= 9 && code <= 0x10ffff) {
26	        try { return String.fromCodePoint(code); } catch (e) { return ' '; /* FAIL-OPEN: an invalid code point in hostile source HTML degrades to a space, the honest substitute; nothing is hidden. */ }
27	      }
28	    }
29	    return m;
30	  });
31	}
32	
33	// stripHtml(html) -> visible text only. Raw-text and non-content elements are dropped whole (tolerant of
34	// "</script >" whitespace, caution.md html-text D-01), block closers become newlines so footer lines
35	// survive, remaining tags become spaces, entities are decoded, whitespace is collapsed.
36	function stripHtml(html) {
37	  let s = String(html);
38	  s = s.replace(/<!--[\s\S]*?-->/g, ' ');
39	  s = s.replace(/<(script|style|noscript|template|svg|iframe|head)\b[\s\S]*?<\/\1\s*>/gi, ' ');
40	  s = s.replace(/<\/(p|div|li|ul|ol|h[1-6]|tr|td|th|section|article|footer|header|nav|br)\s*>/gi, '\n');
41	  s = s.replace(/<br\s*\/?>/gi, '\n');
42	  s = s.replace(/<[^>]+>/g, ' ');
43	  s = decodeEntities(s);
44	  s = s.replace(/[ \t\r\f\v]+/g, ' ');
45	  s = s.replace(/ ?\n ?/g, '\n');
46	  s = s.replace(/\n{3,}/g, '\n\n');
47	  return s.trim();
48	}
49	
50	function extractTitle(html) {
51	  const m = /<title[^>]*>([\s\S]*?)<\/title\s*>/i.exec(String(html));
52	  return m ? decodeEntities(m[1]).replace(/\s+/g, ' ').trim() : '';
53	}
54	
55	// extractOgMeta(html) -> a map of Open Graph meta values keyed by the property SUFFIX (og.site_name,
56	// og.title, ...). Generic on purpose: the identity-signal property name is never hardcoded here (the
57	// og: prefix plus a captured suffix), so extract.js surfaces the raw corpus value while identity
58	// RESOLUTION (legal_name/display_name from the site name) stays the one door in facts/identity.js.
59	function extractOgMeta(html) {
60	  const out = {};
61	  const re = /<meta\b[^>]*>/gi;
62	  let m;
63	  while ((m = re.exec(String(html))) !== null) {
64	    const p = /property\s*=\s*["']og:([a-z_]+)["']/i.exec(m[0]);
65	    if (!p) continue;
66	    const c = /content\s*=\s*["']([^"']*)["']/i.exec(m[0]);
67	    if (c) out[p[1].toLowerCase()] = decodeEntities(c[1]).trim();
68	  }
69	  return out;
70	}
71	
72	function extractJsonLd(html) {
73	  const out = [];
74	  const re = /<script\b[^>]*type\s*=\s*["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script\s*>/gi;
75	  let m;
76	  while ((m = re.exec(String(html))) !== null) {
77	    const raw = m[1].trim();
78	    if (!raw) continue;
79	    try { out.push(JSON.parse(raw)); }
80	    catch (e) { /* FAIL-OPEN: invalid JSON-LD on the live site is a fact about the site; record nothing, fabricate nothing (no partial-parse guesses). */ }
81	  }
82	  return out;
83	}
84	
85	// extractFooterText(html) -> the statutory-disclosure surface (C-034): the concatenated visible text of
86	// every <footer> region, else '' (the crawl caller may fall back to the page tail). Company number,
87	// registered office and SRA/authorisation strings live here; it is a MANDATORY detection surface.
88	function extractFooterText(html) {
89	  const out = [];
90	  const re = /<footer\b[^>]*>([\s\S]*?)<\/footer\s*>/gi;
91	  let m;
92	  while ((m = re.exec(String(html))) !== null) { const t = stripHtml(m[1]); if (t) out.push(t); }
93	  return out.join('\n').trim();
94	}
95	
96	// extractHrefs(html) -> every raw href value in the document (query strings kept, C-027). Resolution and
97	// same-site filtering are the crawl layer's job (via the tools/lib/safe-fetch.js parsed-host door).
98	function extractHrefs(html) {
99	  const out = [];
100	  const re = /href\s*=\s*["']([^"']+)["']/gi;
101	  let m;
102	  while ((m = re.exec(String(html))) !== null && out.length < 2000) out.push(decodeEntities(m[1]).trim());
103	  return out;
104	}
105	
106	function buildPage(url, html) {
107	  const page = { url, title: extractTitle(html), text: stripHtml(html), jsonLd: extractJsonLd(html) };
108	  const og = extractOgMeta(html);
109	  if (og.site_name !== undefined) page.ogSiteName = og.site_name;
110	  return page;
111	}
112	
113	// ── content classification (C-031 / C-032 / C-038): never let a wall/login/error/shell flip reachable ──
114	const CHALLENGE_MARKERS = [
115	  'just a moment', 'attention required', 'checking your browser', 'verify you are human',
116	  'access denied', 'ddos protection', 'cf-challenge', 'enable javascript and cookies to continue',
117	  'captcha', 'request unsuccessful', 'incapsula', 'perimeterx', 'are you a robot',
118	];
119	const WALL_STATUSES = new Set([401, 403, 429, 503]);
120	const LOGIN_MARKERS = /(sign in|signin|log in|login|log ?into|please (?:sign|log) in|enter your (?:password|username)|forgot your password)/i;
121	
122	function looksChallenge(status, text, title) {
123	  if (WALL_STATUSES.has(status)) return true;
124	  const hay = ((title || '') + '\n' + String(text || '').slice(0, 2500)).toLowerCase();
125	  if (!hay.trim()) return false;
126	  return CHALLENGE_MARKERS.some((mk) => hay.includes(mk)) && String(text || '').length < 4000;
127	}
128	
129	// looksLogin: the WHOLE page is a sign-in gate, not a content page that merely links to a client login.
130	// Guarded by content dominance (thin visible text OR a password field on a short page), never byte count
131	// alone (caution.md C-031).
132	function looksLogin(html, text) {
133	  const t = String(text || '');
134	  if (!LOGIN_MARKERS.test((t + ' ' + extractTitle(html)))) return false;
135	  const hasPasswordField = /<input\b[^>]*type\s*=\s*["']password["']/i.test(String(html));
136	  if (t.length < 600) return true;
137	  return hasPasswordField && t.length < 1500;
138	}
139	
140	// looksSpaShell: HTTP 200, an HTML document, but near-zero visible text (C-032, royalparkpartners.com).
141	function looksSpaShell(html, text) {
142	  if (String(text || '').length >= 200) return false;
143	  const body = String(html || '');
144	  if (!/<html[\s>]/i.test(body) && !/<div/i.test(body)) return false;
145	  return /<div[^>]*id\s*=\s*["'](root|app|__next|___gatsby)["']/i.test(body) || /<script/i.test(body);
146	}
147	
148	// pageContentClass(status, html) -> 'content' | 'challenge' | 'login' | 'error' | 'empty'. Only 'content'
149	// enters the corpus and counts toward reachability; every other class is honestly withheld.
150	function pageContentClass(status, html) {
151	  const st = Number(status) || 0;
152	  if (st >= 500 || st === 404 || st === 410) return 'error';
153	  const text = stripHtml(html);
154	  if (looksChallenge(st, text, extractTitle(html))) return 'challenge';
155	  if (looksLogin(html, text)) return 'login';
156	  if (looksSpaShell(html, text)) return 'empty';
157	  if (text.length < 20) return 'empty';
158	  return 'content';
159	}
160	
161	module.exports = {
162	  decodeEntities, stripHtml, extractTitle, extractOgMeta, extractJsonLd,
163	  extractFooterText, extractHrefs, buildPage, pageContentClass,
164	};
