1	'use strict';
2	/**
3	 * documents.js - follow footer-linked policy documents and read them, HONESTLY (caution.md C-033).
4	 *
5	 * Footer-linked policy documents and external PDFs (Lomond, Dutch & Dutch privacy/MSA/fees PDFs) were
6	 * never read, so "missing" findings fired on obligations whose evidence was in a linked PDF. This lane
7	 * follows those links and reads what it CAN with a zero-dependency route:
8	 *
9	 *   - HTML policy documents ARE parseable with the crawler's stripper -> {parsed:true, text}.
10	 *   - PDFs are NOT: there is no reliable zero-dependency PDF text extractor, and an honest gap beats a bad
11	 *     parser (a mis-extracted policy is worse than a known-unread one). Every PDF is recorded LOUDLY as
12	 *     {url, fetched:true, parsed:false, reason:'no-parser'} on the bundle, its note pushed to the log, and
13	 *     its page-class returned in `unparsedClasses` so the coverage interlock (C-024/C-033) demotes any
14	 *     obligation that depends on it to needs-review instead of asserting an absence.
15	 *
16	 * No new dependency is introduced (Constitution: zero runtime npm deps). Effects are INJECTED: fetchFn
17	 * (async url -> {ok,status,body,finalUrl,contentType}) and the deadline timers, so node:test runs offline.
18	 */
19	
20	const { withDeadline } = require('../crawler/pool.js');
21	const { stripHtml } = require('../crawler/extract.js');
22	const { classify } = require('../crawler/coverage-contract.js');
23	const safeFetch = require('../../tools/lib/safe-fetch.js');
24	
25	const POLICY_DOC_RX = /privacy|cookie|terms|conditions|legal|complaint|fees|pricing|returns|refund|data[-_ ]protection|gdpr|modern[-_ ]slavery|disclosure|imprint/i;
26	const DOC_ASSET_RX = /\.(pdf|doc|docx|rtf)(\?|#|$)/i;
27	const DEFAULT_MAX_DOCS = 12;
28	
29	// isPolicyDocLink(url) -> true when a footer href is worth following as a policy document: a policy-named
30	// page OR any document-asset download (pdf/doc). Query strings are kept (C-027); host safety is the
31	// caller's (the crawl passes same-site footer links).
32	function isPolicyDocLink(url) {
33	  const u = String(url || '');
34	  if (safeFetch.isNonCrawlable(u)) return false;
35	  return POLICY_DOC_RX.test(u) || DOC_ASSET_RX.test(u);
36	}
37	
38	// isPdfLike(url, contentType) -> true for a PDF (or other binary doc) by extension or content-type.
39	function isPdfLike(url, contentType) {
40	  if (/(application\/pdf|application\/msword|officedocument)/i.test(String(contentType || ''))) return true;
41	  return DOC_ASSET_RX.test(String(url || ''));
42	}
43	
44	// classifyDoc(url) -> the coverage page-class this document would satisfy (reuses the crawl classifier so
45	// there is one page-class door). A generic legal doc maps to its class; anything else is 'other'.
46	function classifyDoc(url) {
47	  return classify({ url });
48	}
49	
50	// readOneDocument(url, opts) -> the honest record for one document. HTML is parsed to text; a PDF/binary
51	// is recorded {parsed:false, reason:'no-parser'} and logged loudly; an unreachable doc is {fetched:false}.
52	async function readOneDocument(url, opts) {
53	  const pageClass = classifyDoc(url);
54	  let res;
55	  try { res = await withDeadline(() => opts.fetchFn(url), opts.deadlineMs, opts.timers); }
56	  catch (e) { opts.log('document-unreachable', url + ': ' + e.message); return { url, fetched: false, parsed: false, reason: 'fetch-failed: ' + e.message, pageClass }; /* FAIL-OPEN: one document's fetch failure/timeout is RECORDED (logged via opts.log AND returned as fetched:false, reason:'fetch-failed'), then the lane continues; an unreachable document must not abort the whole crawl, and its absence is never asserted (it stays out of unparsedClasses so no obligation is demoted on it). */ }
57	  if (!res || !res.ok || !res.body) return { url, fetched: Boolean(res && res.status), parsed: false, reason: 'unreachable-or-empty', pageClass };
58	  if (isPdfLike(url, res.contentType)) {
59	    opts.log('document-no-parser', url + ': fetched a PDF/binary policy document but there is no zero-dependency parser; recorded parsed:false (C-033 - obligations relying on this page-class demote to needs-review)');
60	    return { url, fetched: true, parsed: false, reason: 'no-parser', contentType: res.contentType || null, pageClass };
61	  }
62	  const text = stripHtml(res.body);
63	  if (text.length < 40) return { url, fetched: true, parsed: false, reason: 'empty-after-strip', pageClass };
64	  return { url, fetched: true, parsed: true, text, pageClass };
65	}
66	
67	// collectDocuments(footerLinks, opts) -> { documents, unparsed, unparsedClasses, notes }. Every fetched-
68	// but-unparsed document contributes its page-class to `unparsedClasses`, the set the coverage contract
69	// consumes for the absence-demotion interlock. Pure over its injected effects; never throws.
70	async function collectDocuments(footerLinks, opts = {}) {
71	  const notes = [];
72	  const log = typeof opts.log === 'function' ? opts.log : (kind, msg) => notes.push({ kind, msg });
73	  const fetchFn = opts.fetchFn;
74	  if (typeof fetchFn !== 'function') return { documents: [], unparsed: [], unparsedClasses: new Set(), notes };
75	  const inner = { fetchFn, deadlineMs: opts.deadlineMs || 15000, timers: opts.timers, log };
76	  const seen = new Set();
77	  const targets = [];
78	  for (const link of footerLinks || []) {
79	    if (!isPolicyDocLink(link)) continue;
80	    const key = String(link).split('#')[0];
81	    if (seen.has(key)) continue;
82	    seen.add(key);
83	    targets.push(key);
84	    if (targets.length >= (opts.maxDocs || DEFAULT_MAX_DOCS)) break;
85	  }
86	  const documents = await Promise.all(targets.map((u) => readOneDocument(u, inner)));
87	  const unparsed = documents.filter((d) => d.fetched && !d.parsed);
88	  const unparsedClasses = new Set(unparsed.map((d) => d.pageClass).filter((c) => c && c !== 'other'));
89	  return { documents, unparsed, unparsedClasses, notes };
90	}
91	
92	module.exports = { collectDocuments, isPolicyDocLink, isPdfLike, classifyDoc, readOneDocument };
