1	'use strict';
2	// extract.test.js - the ONE producer of stripped visible text and the content classifier.
3	
4	const test = require('node:test');
5	const assert = require('node:assert');
6	
7	const ex = require('./extract.js');
8	
9	test('stripHtml keeps visible text only: script/style/noscript dropped, entities decoded, whitespace collapsed', () => {
10	  const html = '<html><head><style>.x{color:red}</style><script>var a=1<2;</script></head>'
11	    + '<body><h1>Hello&nbsp;&amp; welcome</h1><p>Line one</p><p>Line two</p><noscript>enable js</noscript></body></html>';
12	  const text = ex.stripHtml(html);
13	  assert.ok(!/color:red|var a/.test(text), 'script/style contents never enter the corpus (C-012)');
14	  assert.ok(!/enable js/.test(text), 'noscript is dropped');
15	  assert.match(text, /Hello & welcome/);
16	  assert.match(text, /Line one\nLine two/, 'block closers become newlines so footer lines survive');
17	});
18	
19	test('stripHtml tolerates whitespace in closing tags (</script >)', () => {
20	  assert.ok(!/secret/.test(ex.stripHtml('<script >var s="secret"</script >visible')));
21	});
22	
23	test('decodeEntities: named, numeric decimal, numeric hex, and malformed references', () => {
24	  assert.equal(ex.decodeEntities('a&amp;b'), 'a&b');
25	  assert.equal(ex.decodeEntities('&#65;&#x42;'), 'AB');
26	  assert.equal(ex.decodeEntities('&pound;10'), '£10');
27	  assert.equal(ex.decodeEntities('&notareal;'), '&notareal;', 'an unknown entity is left intact, never guessed');
28	});
29	
30	test('extractTitle and extractFooterText (the mandatory disclosure surface, C-034)', () => {
