  // nothing", it must not be coalesced by `||` into the 15000/12 default. Nullish/negative/NaN falls back.
  const deadlineMs = Number.isFinite(opts.deadlineMs) && opts.deadlineMs >= 0 ? opts.deadlineMs : 15000;
  const maxDocs = Number.isFinite(opts.maxDocs) && opts.maxDocs >= 0 ? opts.maxDocs : DEFAULT_MAX_DOCS;
  const inner = { fetchFn, deadlineMs, timers: opts.timers, log };
  const seen = new Set();
  const targets = [];
  for (const link of footerLinks || []) {
    if (targets.length >= maxDocs) break; // checked BEFORE adding so maxDocs:0 follows zero documents
    if (!isPolicyDocLink(link)) continue;
    const key = String(link).split('#')[0];
    if (seen.has(key)) continue;
    seen.add(key);
    targets.push(key);
  }
  const documents = await Promise.all(targets.map((u) => readOneDocument(u, inner)));
  // The demotion set = every document we FOUND but could not read: fetched-but-unparsed (PDF/empty) OR
  // unread (timeout/transport error/5xx/403/empty-body). A 404/410 (unread:false, fetched:false) is a
  // broken link that demotes nothing. 'other'-class pages carry no obligation, so they never demote.
  const unparsed = documents.filter((d) => (d.fetched && !d.parsed) || d.unread === true);
  const unparsedClasses = new Set(unparsed.map((d) => d.pageClass).filter((c) => c && c !== 'other'));
  return { documents, unparsed, unparsedClasses, notes };
}

