1	'use strict';
2	// evidence/registers/sra.js — the SRA (Solicitors Regulation Authority) Data Sharing Platform,
3	// organisation search. Port source: cowork-os-fresh src/lib/compliance/register-grounding.js (the
4	// SRA entry: base https://data.sra.org.uk, path /organisations?name=... — a public organisation
5	// search that answers a bare JSON array, no subscription key required for this endpoint).
6	// Strengthened here with the shared name-match gate (C-004): the old register-grounding.js treated
7	// ANY non-empty array as establishment evidence with no scoring at all.
8	const { runLookup } = require('./lib/lookup-runner');
9	const { makeNote } = require('./lib/notes');
10	
11	const SEARCH_BASE = 'https://data.sra.org.uk/organisations';
12	
13	// Only a law-firms/barristers caller should pay for this lookup (Rule 8: budgets are caps, and an
14	// irrelevant register call is a wasted one). An unspecified sector still tries: the register itself
15	// can corroborate or contradict a sector guess (caution C-014), so withholding the call just because
16	// the sector is not yet known would defeat that purpose.
17	const APPLICABLE_SECTORS = new Set(['law-firms', 'barristers']);
18	function applies(sector) {
19	  return !sector || APPLICABLE_SECTORS.has(String(sector).toLowerCase());
20	}
21	
22	function buildRequest(query, apiToken) {
23	  const headers = apiToken ? { Authorization: 'Bearer ' + apiToken } : {};
24	  const url = SEARCH_BASE + '?name=' + encodeURIComponent(query.slice(0, 80));
25	  return { url, headers, requestKey: 'sra.organisations' };
26	}
27	
28	// extractCandidates(json) -> [{name, raw}]. The endpoint answers a bare array of organisation
29	// objects; each candidate's display name may arrive under either camelCase or snake_case field name
30	// depending on the API version fetched.
31	function extractCandidates(json) {
32	  const items = Array.isArray(json) ? json : [];
33	  return items
34	    .filter((it) => it && (it.organisationName || it.name))
35	    .map((it) => ({ name: String(it.organisationName || it.name || ''), raw: it }));
36	}
37	
38	function addressLine(raw) {
39	  const parts = [raw.addressLine1, raw.town, raw.postcode].filter(Boolean);
40	  return parts.length ? parts.join(', ') : null;
41	}
42	
43	function buildRow(candidate) {
44	  const raw = candidate.raw;
45	  return {
46	    organisation_name: candidate.name || null,
47	    sra_number: raw.sraNumber || raw.sra_number || null,
48	    firm_type: raw.firmType || raw.firm_type || null,
49	    registered_office_address: addressLine(raw),
50	  };
51	}
52	
53	async function lookupSra({ query, sector, fetchFn, deadlineMs, keys, log }) {
54	  if (!applies(sector)) {
55	    const detail = 'sector "' + sector + '" is not law-firms/barristers; SRA lookup skipped (Rule 8 budget cap)';
56	    return { row: null, note: makeNote('sra', 'skipped', 'sector_not_applicable', detail, log) };
57	  }
58	  const apiToken = keys && keys.sra;
59	  return runLookup({
60	    register: 'sra',
61	    query,
62	    fetchFn,
63	    deadlineMs,
64	    log,
65	    requiredKeyNote: null, // the organisation search endpoint is publicly queryable without a key
66	    buildRequest: () => buildRequest(query, apiToken),
67	    extractCandidates,
68	    buildRow,
69	  });
70	}
71	
72	module.exports = { lookupSra, applies, extractCandidates, buildRow };
