1	'use strict';
2	// evidence/registers/lib/name-match.js — the ONE name-match algorithm every register module in this
3	// directory shares (Constitution C-004): a register row may be returned ONLY on a genuine name match
4	// against the query, never merely because an API answered HTTP 200 with a non-empty body. Ported and
5	// strengthened from the old estate's register-check.js / register-grounding.js, which accepted ANY
6	// non-empty response as establishment evidence, and ico-register.js's SQL prefix match, which had no
7	// scoring and no rejection of a merely-similar name.
8	//
9	// ALGORITHM: normalise both names (lowercase, "&" -> "and", strip legal-entity suffixes via the one
10	// vocabulary door facts/vocabulary.js, collapse whitespace), tokenise on non-alphanumeric boundaries
11	// dropping short/connective tokens, then score by Jaccard similarity (shared tokens divided by the
12	// union of tokens). A match requires the score to clear MATCH_THRESHOLD AND at least one shared
13	// token. This is deliberately NOT a substring or prefix test (a substring/prefix match on a
14	// host/name is the C-059 class this codebase bans lint-wide) and deliberately not "any shared word",
15	// which is exactly what let a register hit attach to an unrelated company in the old estate sharing
16	// only a generic first word.
17	//
18	// THRESHOLD JUSTIFICATION (MATCH_THRESHOLD = 0.6):
19	//  - An exact or suffix-only-differing name (the overwhelming common case: the query and the register
20	//    row differ only by a legal suffix such as LLP/Ltd) normalises to identical token sets, so the
21	//    score is 1.0.
22	//  - A register variant carrying one extra token the query lacks (a common real shape: the query is a
23	//    shortened trading name and the register row spells out a fuller form) still clears the threshold
24	//    with margin: two shared tokens out of a three-token union scores 0.667.
25	//  - A two-word query sharing only its FIRST word with an unrelated two-word candidate — the
26	//    "Kingsley Napley LLP" vs "Kingsley Carpets Ltd" class this module exists to reject — scores
27	//    0.333 (one shared token out of a three-token union), comfortably below the threshold.
28	//  - 0.6 sits in the gap between these two real shapes with margin on both sides; it is not tuned to
29	//    a single fixture value. See name-match.test.js and the eval/calibration-known-bad/fixtures/
30	//    p3-register-*.json fixtures for both directions (true positive still fires, near-miss stays
31	//    rejected).
32	//
33	// A single shared token is required even when the ratio alone would pass, as defence in depth for
34	// very short names; a one-token query matching a one-token candidate exactly already scores 1.0 and
35	// satisfies both conditions, so this changes nothing for the common short-name case.
36	
37	let LEGAL_ENTITY_SUFFIXES;
38	let PUBLIC_SUFFIX_SECOND_LEVEL;
39	try {
40	  ({ LEGAL_ENTITY_SUFFIXES, PUBLIC_SUFFIX_SECOND_LEVEL } = require('../../../facts/vocabulary.js'));
41	} catch (err) {
42	  // facts/vocabulary.js is the one door for this word list (Constitution Rule 1); if it is ever
43	  // absent this module must fail closed and loudly rather than silently matching against an empty
44	  // suffix list, which would make every legal-suffix token count toward the name score and inflate
45	  // every match.
46	  throw new Error(
47	    'evidence/registers/lib/name-match.js: facts/vocabulary.js is required for LEGAL_ENTITY_SUFFIXES '
48	    + 'and PUBLIC_SUFFIX_SECOND_LEVEL and could not be loaded: ' + err.message
49	  );
50	}
51	
52	const MIN_TOKEN_CHARS = 3;
53	const MIN_QUERY_LEN = 4; // a normalised query shorter than this is too ambiguous to search safely
54	const MATCH_THRESHOLD = 0.6;
55	
56	const CONNECTIVE_WORDS = new Set(['and', 'the', 'of', 'for']);
57	
58	const SUFFIX_BODY = '\\b(?:'
59	  + LEGAL_ENTITY_SUFFIXES.map((s) => String(s).replace(/[.*+?^${}()|[\]\\]/g, '\\$&')).join('|')
60	  + ')\\b\\.?';
61	const SUFFIX_RX = new RegExp(SUFFIX_BODY, 'gi');
62	
63	function tidy(s) {
64	  return String(s == null ? '' : s).replace(/\s+/g, ' ').trim();
65	}
66	
67	function stripLegalSuffixes(s) {
68	  return tidy(String(s || '').replace(SUFFIX_RX, ' '));
69	}
70	
71	function normaliseName(name) {
72	  const lowered = String(name || '').toLowerCase().replace(/&/g, ' and ');
