357	// compileCatalogue(catalogue) -> { specs, rejected }. Every obligation of every record becomes a spec;
358	// each spec is validated at the source (C-009/C-019), and any spec carrying an unanchored/bare pattern
359	// is REJECTED here with its reasons rather than shipped - an unanchored pattern is unrepresentable in
360	// what propose.js consumes.
361	function compileCatalogue(catalogue) {
362	  const specs = [];
363	  const rejected = [];
364	  for (const record of recordsOf(catalogue)) {
365	    for (const spec of compileRecordSpecs(record)) {
366	      const v = validateSpec(spec);
367	      if (v.valid) specs.push(spec);
368	      else rejected.push({ record_id: spec.record_id, duty_idx: spec.duty_idx, errors: v.errors });
369	    }
370	  }
