375	// isAnchoredPatternValue(pattern) -> { ok, reason }. A pattern is REJECTED when it is bare/unanchored:
376	//   - anchored-regex: source must contain a \b word boundary or a ^/$ anchor AND must compile; a bare
377	//     alternation like "EU" or a bare substring like "cost" (no \b, no ^/$) is rejected (C-019/C-044/C-059).
378	//   - token-set: non-empty; every token >= MIN_TOKEN_LEN and a clean word (a 1-2 char or punctuation
379	//     token would substring-match, the "post"->postcode class C-059).
380	//   - url-path: a rooted single path segment ('/xxx'), never a bare word (the /cost-of-living class C-044).
381	function isAnchoredPatternValue(pattern) {
382	  if (!pattern || typeof pattern !== 'object') return { ok: false, reason: 'pattern is not an object' };
383	  if (!PATTERN_KINDS.includes(pattern.kind)) return { ok: false, reason: 'unknown pattern kind ' + JSON.stringify(pattern.kind) };
384	  if (pattern.kind === 'anchored-regex') return anchoredRegexOk(pattern.value);
385	  if (pattern.kind === 'token-set') return tokenSetOk(pattern.value);
386	  return urlPathOk(pattern.value);
387	}
