389	// REDOS_RX: catastrophic-backtracking constructs unrepresentable in a DERIVED anchored-regex (Rob P0:
390	// derived token-set lookaheads with [\s\S]* hung on real corpora). A derived phrase pattern is a
391	// `\b`-bounded word run joined by `\W+` and legitimately never needs any of these, so this rule fires
392	// only on a regression that reintroduces a ReDoS vector:
393	//   \(\?[=!<]        any lookaround (the old 'all' co-occurrence used (?=[\s\S]*...))
394	//   \[\\s\\S\]\*     an unbounded [\s\S]* (or [\S\s]*) wildcard star
395	//   (?:^|[^\\])\.\*  an unescaped .* dot-star ([^\\] so an escaped \.  literal dot is not flagged)
396	const REDOS_RX = /\(\?[=!<]|\[\\s\\S\]\*|\[\\S\\s\]\*|(?:^|[^\\])\.\*/;
397	// NESTED_QUANT_RX: a quantified group immediately re-quantified ((a+)+, (\w*)* ...), the classic
398	// exponential ReDoS. `\W+`/`\W*` are unparenthesised single quantifiers and never match this.
399	const NESTED_QUANT_RX = /\([^)]*[+*][^)]*\)\s*[+*]/;
